    def dump_checkpoint(self, weights_only: Optional[bool] = None) -> dict[str, Any]:
        """Create a checkpoint dictionary with all trainer and model states.

        Args:
            weights_only: If ``True``, only include model weights.

        Returns:
            A dictionary containing the checkpoint data.
        """
        trainer = self.trainer
        checkpoint: dict[str, Any] = {}

        # Basic trainer state
        checkpoint["epoch"] = trainer.current_epoch
        checkpoint["global_step"] = trainer.global_step
        checkpoint["version"] = trainer._loggers if hasattr(trainer, "_loggers") else None

        # Model state dict
        checkpoint["state_dict"] = trainer.strategy.lightning_module_state_dict()

        # Hyperparameters
        if hasattr(trainer.lightning_module, "hparams"):
            checkpoint["hyper_parameters"] = dict(trainer.lightning_module.hparams)

        # Loop states
        checkpoint["loops"] = {
            "fit_loop": trainer.fit_loop.state_dict(),
        }

        # Callback states
        checkpoint["callbacks"] = {}
        for callback in trainer.callbacks:
            if hasattr(callback, "state_dict"):
                callback_state = callback.state_dict()
                if callback_state:
                    checkpoint["callbacks"][callback.__class__.__qualname__] = callback_state

        # Optimizer states
        if trainer.state.fn == TrainerFn.FITTING:
            checkpoint["optimizer_states"] = []
            for optimizer in trainer.optimizers:
                checkpoint["optimizer_states"].append(optimizer.state_dict())

            # Scheduler states
            checkpoint["lr_schedulers"] = []
            for config in trainer.lr_scheduler_configs:
                scheduler = config.scheduler
                if hasattr(scheduler, "state_dict"):
                    checkpoint["lr_schedulers"].append(scheduler.state_dict())

        # Precision plugin state
        precision_plugin = trainer.strategy.precision_plugin
        if hasattr(precision_plugin, "state_dict"):
            checkpoint["precision_plugin"] = precision_plugin.state_dict()

        # Datamodule state
        if trainer.datamodule is not None:
            datamodule_state = {}
            if hasattr(trainer.datamodule, "state_dict"):
                datamodule_state = trainer.datamodule.state_dict()
            if datamodule_state:
                checkpoint[trainer.datamodule.__class__.__qualname__] = datamodule_state

        # Save hooks
        call._call_callbacks_on_save_checkpoint(trainer, checkpoint)
